-- Cleanup Script: Delete all parlamentarians and non-admin users\n-- Preserve ONLY admin@diputados.bo\n\n-- 1. Verify admin exists\nSELECT 'Admin check:' as step, COUNT(*) as count FROM user_profiles WHERE email = 'admin@diputados.bo';\n\n-- 2. Show current counts\nSELECT 'User profiles total:' as table, COUNT(*) as count FROM user_profiles\nUNION ALL\nSELECT 'Parlamentarians total:' as table, COUNT(*) as count FROM parliamentarians\nUNION ALL\nSELECT 'Non-admin users:' as table, COUNT(*) as count FROM user_profiles WHERE email != 'admin@diputados.bo';\n\n-- 3. DELETE ALL parlamentarians (safe)\nDELETE FROM parliamentarians;\n\n-- 4. DELETE all user_profiles except admin@diputados.bo (cascades to auth.users)\nDELETE FROM user_profiles WHERE email != 'admin@diputados.bo';\n\n-- 5. Verify final state\nSELECT 'Final user profiles:' as step, COUNT(*) as count FROM user_profiles;\nSELECT 'Final parlamentarians:' as step, COUNT(*) as count FROM parliamentarians;\nSELECT * FROM user_profiles WHERE email = 'admin@diputados.bo';\n\n-- COMMIT;  (Supabase auto-commits, but wrap in transaction if needed)\n
